import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Photo } from '../../core/models';
import { AvatarComponent } from '../../shared/avatar/avatar.component';

@Component({
  selector: 'app-profile-edit',
  standalone: true,
  imports: [CommonModule, FormsModule, AvatarComponent],
  templateUrl: './profile-edit.component.html',
  styleUrl: './profile-edit.component.css',
})
export class ProfileEditComponent {
  private auth = inject(AuthService);
  private router = inject(Router);
  private route = inject(ActivatedRoute);

  readonly user = this.auth.user;
  readonly onboarding = this.route.snapshot.queryParamMap.get('onboarding') === '1';

  // Backend-provided data — typed signal per the data contract.
  readonly photos = signal<Photo[]>([
    { id: 'p1', url: '', sortOrder: 0 },
    { id: 'p2', url: '', sortOrder: 1 },
  ]);

  readonly bio = signal<string>(
    'Design lead who cares about the details most people never notice. Weekend trail runner, incurable ramen scout, and a sucker for a well-argued opinion. Looking for someone curious and warm.',
  );
  readonly jobTitle = signal<string>('Product Design Lead');
  readonly employer = signal<string>('Northwind Labs');
  readonly saved = signal(false);

  readonly maxPhotos = 6;
  readonly canAddPhoto = computed(() => this.photos().length < this.maxPhotos);
  readonly bioCount = computed(() => this.bio().length);
  readonly complete = computed(() => this.bio().trim().length > 0 && this.photos().length > 0);

  addPhoto(): void {
    if (!this.canAddPhoto()) return;
    this.photos.update((list) => [...list, { id: 'p' + (list.length + 1), url: '', sortOrder: list.length }]);
  }

  removePhoto(id: string): void {
    this.photos.update((list) => list.filter((p) => p.id !== id));
  }

  save(): void {
    this.saved.set(true);
    if (this.complete()) {
      this.auth.markProfileComplete();
    }
    if (this.onboarding && this.complete()) {
      this.router.navigate(['/feed']);
      return;
    }
    setTimeout(() => this.saved.set(false), 2200);
  }
}
